// Client requests authentication
FUNCTION requestServiceTicket(serviceName):
 // Step 1: Get TGT from KDC
 tgt = requestTGT(userPassword)

 // Step 2: Request service ticket
 serviceTicket = requestFromKDC(tgt, serviceName)

 // Step 3: Present ticket to service
 accessGranted = service.verify(serviceTicket)

 RETURN accessGranted
